/**
 * Helper function to convert a 3D point array [x, y, z] to a unique string key.
 * @param {number[]} point 
 * @returns {string}
 */
const pointToString = (point) => `${point[0]},${point[1]},${point[2]}`;

/**
 * Helper function to convert a string key back to a 3D point array.
 * Not strictly necessary for this solution but good practice.
 * @param {string} str 
 * @returns {number[]}
 */
const stringToPoint = (str) => str.split(',').map(Number);

function solve(points, target) {
    const targetStr = pointToString(target);

    // P stores all unique point coordinates found so far (as strings).
    const P = new Set();
    // L stores the coordinate arrays corresponding to points in P.
    let L = [];

    // --- Initialization (k=0) ---
    for (const p of points) {
        const pStr = pointToString(p);
        if (!P.has(pStr)) {
            P.add(pStr);
            L.push(p);
        }
    }

    if (P.has(targetStr)) {
        return 0;
    }

    // --- Iterative Generation (k >= 1) ---
    let k = 1;

    while (true) {
        const L_prev = L;
        const generatedNewPoints = [];
        let newPointsFound = false;

        // Generate points for generation k using pairs from L_prev
        // Iterate over all distinct pairs of points (i < j)
        const N_prev = L_prev.length;

        for (let i = 0; i < N_prev; i++) {
            for (let j = i + 1; j < N_prev; j++) {
                const p1 = L_prev[i];
                const p2 = L_prev[j];

                // Calculate midpoint c = [floor((x1 + x2) / 2), ...]
                const newPoint = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const newPointStr = pointToString(newPoint);

                // Check if this point is truly new to the entire set P
                if (!P.has(newPointStr)) {
                    generatedNewPoints.push(newPoint);
                    newPointsFound = true;
                }
            }
        }

        if (!newPointsFound) {
            // No new unique points were generated, so the target will never be reached.
            return -1;
        }

        // Update the state: P and L include the newly generated points
        for (const p of generatedNewPoints) {
            const pStr = pointToString(p);
            P.add(pStr);
            L.push(p);
        }

        // Check if the target was found in this generation
        if (P.has(targetStr)) {
            return k;
        }

        k++;

        // Safety break, although coordinate constraints suggest termination well before this
        // Since max unique points is 343, k cannot exceed 343 in practice if growth happens.
        if (L.length > 343 + points.length) {
             return -1;
        }
    }
}

