def solve(points : Array(Array(Int64)), target : Array(Int64)) : Int64 {
    fn point_to_string(point: Array(Int64)) -> String {
        point.join(",")
    }

    let target_str = point_to_string(target)

    // P stores all unique point coordinates found so far (as strings).
    var P = Set(String.new())
    // L stores the coordinate arrays corresponding to points in P.
    var L = Array(Array(Int64).new())

    // --- Initialization (k=0) ---
    for p in points {
        let p_str = point_to_string(p)
        if !P.contains(p_str) {
            P.add(p_str)
            L.push(p)
        }
    }

    if P.contains(target_str) {
        return 0
    }

    // --- Iterative Generation (k >= 1) ---
    var k = 1

    loop {
        let L_prev = L // Reference to all points available up to k-1
        var generated_new_points = Array(Array(Int64).new())
        var new_points_found = false

        // Generate points for generation k using pairs from L_prev
        // Iterate over all distinct pairs of points (i < j)
        let N_prev = L_prev.len

        for i in 0..(N_prev - 1) {
            for j in (i + 1).. (N_prev - 1) {
                let p1 = L_prev[i]
                let p2 = L_prev[j]

                // Calculate midpoint c = [floor((x1 + x2) / 2), ...]
                // In Crystal, integer division (/) inherently floors towards zero. Since all coordinates are non-negative, this is equivalent to floor().
                let new_point = [
                    (p1[0] + p2[0]) / 2,
                    (p1[1] + p2[1]) / 2,
                    (p1[2] + p2[2]) / 2
                ]

                let new_point_str = point_to_string(new_point)

                // Check if this point is truly new to the entire set P
                if !P.contains(new_point_str) {
                    generated_new_points.push(new_point)
                    new_points_found = true
                }
            }
        }

        if !new_points_found {
            // No new unique points were generated, so the target will never be reached.
            return -1
        }

        // Update the state: P and L include the newly generated points
        for p in generated_new_points {
            let p_str = point_to_string(p)
            P.add(p_str)
            L.push(p)
        }

        // Check if the target was found in this generation
        if P.contains(target_str) {
            return k
        }

        k += 1
    }
